 1→import { computed } from 'vue'
 2→import { useAuthStore } from '@/stores/auth'
 3→import { ROLE_PERMISSIONS } from '@/utils/permissions'
 4→
 5→export function usePermission() {
 6→  const authStore = useAuthStore()
 7→
 8→  function hasRole(role: string): boolean {
 9→    return authStore.hasRole(role)
10→  }
11→
12→  function hasPermission(permission: string): boolean {
13→    return authStore.hasPermission(permission)
14→  }
15→
16→  function hasAnyRole(roles: string[]): boolean {
17→    return roles.some(role => authStore.hasRole(role))
18→  }
19→
20→  function hasAllPermissions(permissions: string[]): boolean {
21→    return permissions.every(perm => authStore.hasPermission(perm))
22→  }
23→
24→  function canAccess(route: string): boolean {
25→    const roleRouteMap: Record<string, string[]> = {
26→      ADMINISTRATOR: ['admin'],
27→      CONTENT_CURATOR: ['curator'],
28→      INSTRUCTOR: ['instructor', 'ta'],
29→      TEACHING_ASSISTANT: ['ta'],
30→      STUDENT: ['student']
31→    }
32→
33→    for (const role of authStore.roles) {
34→      const allowedPrefixes = roleRouteMap[role] || []
35→      if (allowedPrefixes.some(prefix => route.startsWith(prefix) || route.startsWith(`/${prefix}`))) {
36→        return true
37→      }
38→    }
39→
40→    return false
41→  }
42→
43→  const effectivePermissions = computed(() => {
44→    const perms = new Set<string>(authStore.permissions)
45→    for (const role of authStore.roles) {
46→      const rolePerms = ROLE_PERMISSIONS[role] || []
47→      rolePerms.forEach(p => perms.add(p))
48→    }
49→    return Array.from(perms)
50→  })
51→
52→  return {
53→    hasRole,
54→    hasPermission,
55→    hasAnyRole,
56→    hasAllPermissions,
57→    canAccess,
58→    effectivePermissions
59→  }
60→}
