 1→package com.scholarops.controller;
 2→
 3→import com.scholarops.model.dto.ApiResponse;
 4→import com.scholarops.model.dto.QuizAssemblyRequest;
 5→import com.scholarops.model.entity.QuizPaper;
 6→import com.scholarops.security.UserDetailsImpl;
 7→import com.scholarops.service.QuizAssemblyService;
 8→import jakarta.validation.Valid;
 9→import org.springframework.format.annotation.DateTimeFormat;
10→import org.springframework.http.HttpStatus;
11→import org.springframework.http.ResponseEntity;
12→import org.springframework.security.access.prepost.PreAuthorize;
13→import org.springframework.security.core.annotation.AuthenticationPrincipal;
14→import org.springframework.web.bind.annotation.*;
15→
16→import java.time.LocalDateTime;
17→import java.util.List;
18→import java.util.Map;
19→
20→@RestController
21→@RequestMapping("/api/quizzes")
22→public class QuizController {
23→
24→    private final QuizAssemblyService quizAssemblyService;
25→
26→    public QuizController(QuizAssemblyService quizAssemblyService) {
27→        this.quizAssemblyService = quizAssemblyService;
28→    }
29→
30→    @PostMapping("/assemble")
31→    @PreAuthorize("hasRole('INSTRUCTOR')")
32→    public ResponseEntity<ApiResponse<QuizPaper>> assembleQuiz(
33→            @Valid @RequestBody QuizAssemblyRequest request,
34→            @AuthenticationPrincipal UserDetailsImpl currentUser) {
35→        QuizPaper quiz = quizAssemblyService.assembleQuiz(request, currentUser.getId());
36→        return ResponseEntity.status(HttpStatus.CREATED).body(ApiResponse.success(quiz));
37→    }
38→
39→    @GetMapping
40→    @PreAuthorize("hasRole('INSTRUCTOR')")
41→    public ResponseEntity<ApiResponse<List<QuizPaper>>> listQuizzes(
42→            @AuthenticationPrincipal UserDetailsImpl currentUser) {
43→        return ResponseEntity.ok(ApiResponse.success(quizAssemblyService.listQuizzes(currentUser.getId())));
44→    }
45→
46→    @GetMapping("/{id}")
47→    @PreAuthorize("hasRole('INSTRUCTOR') or hasRole('STUDENT')")
48→    public ResponseEntity<ApiResponse<QuizPaper>> getQuiz(@PathVariable Long id) {
49→        return ResponseEntity.ok(ApiResponse.success(quizAssemblyService.getQuiz(id)));
50→    }
51→
52→    @PutMapping("/{id}/schedule")
53→    @PreAuthorize("hasRole('INSTRUCTOR')")
54→    public ResponseEntity<ApiResponse<QuizPaper>> scheduleQuiz(@PathVariable Long id,
55→            @RequestBody Map<String, String> body,
56→            @AuthenticationPrincipal UserDetailsImpl currentUser) {
57→        LocalDateTime releaseStart = LocalDateTime.parse(body.get("releaseStart"));
58→        LocalDateTime releaseEnd = LocalDateTime.parse(body.get("releaseEnd"));
59→        return ResponseEntity.ok(ApiResponse.success(
60→                quizAssemblyService.scheduleQuiz(id, releaseStart, releaseEnd, currentUser.getId())));
61→    }
62→
63→    @PutMapping("/{id}/publish")
64→    @PreAuthorize("hasRole('INSTRUCTOR')")
65→    public ResponseEntity<ApiResponse<QuizPaper>> publishQuiz(@PathVariable Long id,
66→            @AuthenticationPrincipal UserDetailsImpl currentUser) {
67→        return ResponseEntity.ok(ApiResponse.success(
68→                quizAssemblyService.publishQuiz(id, currentUser.getId())));
69→    }
70→}
