 1→package com.scholarops.security;
 2→
 3→import jakarta.servlet.FilterChain;
 4→import jakarta.servlet.ServletException;
 5→import jakarta.servlet.http.HttpServletRequest;
 6→import jakarta.servlet.http.HttpServletResponse;
 7→import org.slf4j.Logger;
 8→import org.slf4j.LoggerFactory;
 9→import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
10→import org.springframework.security.core.context.SecurityContextHolder;
11→import org.springframework.security.core.userdetails.UserDetails;
12→import org.springframework.security.web.authentication.WebAuthenticationDetailsSource;
13→import org.springframework.stereotype.Component;
14→import org.springframework.util.StringUtils;
15→import org.springframework.web.filter.OncePerRequestFilter;
16→
17→import java.io.IOException;
18→
19→@Component
20→public class JwtAuthenticationFilter extends OncePerRequestFilter {
21→
22→    private static final Logger logger = LoggerFactory.getLogger(JwtAuthenticationFilter.class);
23→
24→    private final JwtTokenProvider tokenProvider;
25→    private final UserDetailsServiceImpl userDetailsService;
26→
27→    public JwtAuthenticationFilter(JwtTokenProvider tokenProvider, UserDetailsServiceImpl userDetailsService) {
28→        this.tokenProvider = tokenProvider;
29→        this.userDetailsService = userDetailsService;
30→    }
31→
32→    @Override
33→    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response,
34→                                    FilterChain filterChain) throws ServletException, IOException {
35→        try {
36→            String jwt = extractTokenFromRequest(request);
37→            if (StringUtils.hasText(jwt) && tokenProvider.validateToken(jwt)) {
38→                Long userId = tokenProvider.getUserIdFromToken(jwt);
39→                UserDetails userDetails = userDetailsService.loadUserById(userId);
40→
41→                UsernamePasswordAuthenticationToken authentication =
42→                        new UsernamePasswordAuthenticationToken(userDetails, null, userDetails.getAuthorities());
43→                authentication.setDetails(new WebAuthenticationDetailsSource().buildDetails(request));
44→                SecurityContextHolder.getContext().setAuthentication(authentication);
45→            }
46→        } catch (Exception e) {
47→            logger.error("Cannot set user authentication", e);
48→        }
49→
50→        filterChain.doFilter(request, response);
51→    }
52→
53→    private String extractTokenFromRequest(HttpServletRequest request) {
54→        String bearerToken = request.getHeader("Authorization");
55→        if (StringUtils.hasText(bearerToken) && bearerToken.startsWith("Bearer ")) {
56→            return bearerToken.substring(7);
57→        }
58→        return null;
59→    }
60→}
