30→        this.enabled = user.getEnabled();
31→        this.accountLocked = user.getAccountLocked();
32→        this.permissions = permissions;
33→
34→        this.authorities = roles.stream()
35→                .map(role -> new SimpleGrantedAuthority("ROLE_" + role))
36→                .collect(Collectors.toSet());
