 1→import type { NavigationGuardNext, RouteLocationNormalized } from 'vue-router'
 2→import { useAuthStore } from '@/stores/auth'
 3→
 4→export function authGuard(
 5→  to: RouteLocationNormalized,
 6→  from: RouteLocationNormalized,
 7→  next: NavigationGuardNext
 8→): void {
 9→  const authStore = useAuthStore()
10→
11→  // Allow public routes
12→  if (to.meta.public) {
13→    return next()
14→  }
15→
16→  // Redirect unauthenticated users to login
17→  if (!authStore.isAuthenticated) {
18→    return next({
19→      path: '/login',
20→      query: { redirect: to.fullPath }
21→    })
22→  }
23→
24→  // Check role requirements
25→  const requiredRoles = to.meta.roles as string[] | undefined
26→  if (requiredRoles && requiredRoles.length > 0) {
27→    const hasRequiredRole = requiredRoles.some(role => authStore.hasRole(role))
28→    if (!hasRequiredRole) {
29→      return next({ name: 'forbidden' })
30→    }
31→  }
32→
33→  // Check permission requirements
34→  const requiredPermissions = to.meta.permissions as string[] | undefined
35→  if (requiredPermissions && requiredPermissions.length > 0) {
36→    const hasRequiredPermission = requiredPermissions.every(perm => authStore.hasPermission(perm))
37→    if (!hasRequiredPermission) {
38→      return next({ name: 'forbidden' })
39→    }
40→  }
41→
42→  next()
43→}
44→
45→export function guestGuard(
46→  to: RouteLocationNormalized,
47→  from: RouteLocationNormalized,
48→  next: NavigationGuardNext
49→): void {
50→  const authStore = useAuthStore()
51→
52→  if (authStore.isAuthenticated) {
53→    return next({ name: 'dashboard' })
54→  }
55→
56→  next()
57→}
