21→        byte[] keyBytes = new byte[32];
22→        java.util.Arrays.fill(keyBytes, (byte) 0x41);
23→        String base64Key = Base64.getEncoder().encodeToString(keyBytes);
24→        jwtTokenProvider = new JwtTokenProvider(base64Key, 3600000L, 86400000L);
