41→
42→        assertNotNull(token);
43→        assertTrue(jwtTokenProvider.validateToken(token));
44→    }
45→
46→    @Test
47→    void testExpiredToken() {
48→        // Create a provider with 0ms expiration
49→        byte[] keyBytes = new byte[32];
50→        java.util.Arrays.fill(keyBytes, (byte) 0x41);
51→        String base64Key = Base64.getEncoder().encodeToString(keyBytes);
52→        JwtTokenProvider expiredProvider = new JwtTokenProvider(base64Key, 0L, 0L);
53→
54→        Authentication auth = createAuthentication(1L, "testuser");
55→        String token = expiredProvider.generateAccessToken(auth);
56→
57→        assertFalse(expiredProvider.validateToken(token));
58→    }
59→
60→    @Test
61→    void testInvalidToken() {
62→        assertFalse(jwtTokenProvider.validateToken("not.a.valid.token"));
63→        assertFalse(jwtTokenProvider.validateToken(""));
64→    }
65→
66→    @Test
67→    void testGetUserIdFromToken() {
68→        Authentication auth = createAuthentication(42L, "admin");
69→        String token = jwtTokenProvider.generateAccessToken(auth);
70→
71→        Long userId = jwtTokenProvider.getUserIdFromToken(token);
72→        assertEquals(42L, userId);
73→    }
74→}
