 1→package com.scholarops.config;
 2→
 3→import com.scholarops.security.JwtAuthenticationFilter;
 4→import com.scholarops.security.PermissionEvaluatorImpl;
 5→import org.springframework.context.annotation.Bean;
 6→import org.springframework.context.annotation.Configuration;
 7→import org.springframework.security.access.expression.method.DefaultMethodSecurityExpressionHandler;
 8→import org.springframework.security.access.expression.method.MethodSecurityExpressionHandler;
 9→import org.springframework.security.authentication.AuthenticationManager;
10→import org.springframework.security.config.annotation.authentication.configuration.AuthenticationConfiguration;
11→import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity;
12→import org.springframework.security.config.annotation.web.builders.HttpSecurity;
13→import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
14→import org.springframework.security.config.annotation.web.configurers.AbstractHttpConfigurer;
15→import org.springframework.security.config.http.SessionCreationPolicy;
16→import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
17→import org.springframework.security.crypto.password.PasswordEncoder;
18→import org.springframework.security.web.SecurityFilterChain;
19→import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;
20→
21→@Configuration
22→@EnableWebSecurity
23→@EnableMethodSecurity(prePostEnabled = true)
24→public class SecurityConfig {
25→
26→    private final JwtAuthenticationFilter jwtAuthenticationFilter;
27→    private final PermissionEvaluatorImpl permissionEvaluator;
28→
29→    public SecurityConfig(JwtAuthenticationFilter jwtAuthenticationFilter,
30→                          PermissionEvaluatorImpl permissionEvaluator) {
31→        this.jwtAuthenticationFilter = jwtAuthenticationFilter;
32→        this.permissionEvaluator = permissionEvaluator;
33→    }
34→
35→    @Bean
36→    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
37→        http
38→            .csrf(AbstractHttpConfigurer::disable)
39→            .sessionManagement(session -> session.sessionCreationPolicy(SessionCreationPolicy.STATELESS))
40→            .authorizeHttpRequests(auth -> auth
41→                .requestMatchers("/api/auth/login", "/api/auth/refresh").permitAll()
42→                .requestMatchers("/api/**").authenticated()
43→                .anyRequest().denyAll()
44→            )
45→            .addFilterBefore(jwtAuthenticationFilter, UsernamePasswordAuthenticationFilter.class);
46→
47→        return http.build();
48→    }
49→
50→    @Bean
51→    public PasswordEncoder passwordEncoder() {
52→        return new BCryptPasswordEncoder(12);
53→    }
54→
55→    @Bean
56→    public AuthenticationManager authenticationManager(AuthenticationConfiguration config) throws Exception {
57→        return config.getAuthenticationManager();
58→    }
59→
60→    @Bean
61→    public MethodSecurityExpressionHandler methodSecurityExpressionHandler() {
62→        DefaultMethodSecurityExpressionHandler handler = new DefaultMethodSecurityExpressionHandler();
63→        handler.setPermissionEvaluator(permissionEvaluator);
64→        return handler;
65→    }
66→}
