                            .contentType(MediaType.APPLICATION_JSON)
                            .content(objectMapper.writeValueAsString(List.of(score))))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.data.status").value("GRADED"));
        }
    }

