    // Admin cannot access submission or grading endpoints
    // -----------------------------------------------------------------------
    @Nested
    @DisplayName("Admin cannot access submission or grading endpoints")
    class AdminCannotAccessSubmissionsOrGrading {

        @Test
        @WithMockUser(roles = "ADMINISTRATOR")
